const AgentSupport = () => {
  const [tickets, setTickets] = React.useState([
    { id: 101, subject: 'Login not working', requester: 'user@example.com', priority: 'high', status: 'open', updated: '10m ago' },
    { id: 102, subject: 'Feature request: dark mode', requester: 'dev@example.com', priority: 'low', status: 'pending', updated: '2h ago' },
    { id: 103, subject: 'Billing discrepancy', requester: 'finance@example.com', priority: 'critical', status: 'open', updated: '30m ago' },
    { id: 104, subject: 'How to export data?', requester: 'admin@example.com', priority: 'medium', status: 'resolved', updated: '1d ago' }
  ]);
  const [selected, setSelected] = React.useState(null);
  const [reply, setReply] = React.useState('');

  const priorityColor = (p) => ({ critical: '#dc2626', high: '#ea580c', medium: '#ca8a04', low: '#16a34a' }[p] || '#6b7280');
  const statusColor = (s) => ({ open: '#2563eb', pending: '#ca8a04', resolved: '#16a34a', closed: '#6b7280' }[s] || '#6b7280');
  const statusBg = (s) => ({ open: '#eff6ff', pending: '#fefce8', resolved: '#f0fdf4', closed: '#f9fafb' }[s] || '#f9fafb');

  const updateStatus = (id, status) => {
    setTickets(tks => tks.map(t => t.id === id ? { ...t, status, updated: 'Just now' } : t));
  };

  const sendReply = () => {
    if (!reply || !selected) return;
    setReply('');
    setTickets(tks => tks.map(t => t.id === selected.id ? { ...t, status: 'pending', updated: 'Just now' } : t));
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '16px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Customer Support'),
    React.createElement('div', { style: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', flex: 1, minHeight: 0 } },
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '8px', overflow: 'auto' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', marginBottom: '4px', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Tickets'),
        tickets.map(t => React.createElement('div', {
          key: t.id,
          onClick: () => setSelected(t),
          style: {
            background: selected?.id === t.id ? '#e0e7ff' : statusBg(t.status),
            borderRadius: '6px',
            padding: '10px',
            border: selected?.id === t.id ? '1px solid #6366f1' : '1px solid #e5e7eb',
            cursor: 'pointer',
            display: 'flex',
            flexDirection: 'column',
            gap: '4px'
          }
        },
          React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
            React.createElement('span', { style: { fontWeight: 600, fontSize: '13px', color: '#111827' } }, '#', t.id, ' ', t.subject),
            React.createElement('span', { style: { fontSize: '10px', fontWeight: 700, color: priorityColor(t.priority), background: '#fff', padding: '2px 6px', borderRadius: '10px', border: '1px solid ' + priorityColor(t.priority) } }, t.priority)
          ),
          React.createElement('div', { style: { fontSize: '11px', color: '#6b7280' } }, t.requester),
          React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' } },
            React.createElement('span', { style: { fontSize: '11px', fontWeight: 600, color: statusColor(t.status), textTransform: 'uppercase' } }, t.status),
            React.createElement('span', { style: { fontSize: '11px', color: '#9ca3af' } }, t.updated)
          )
        ))
      ),
      React.createElement('div', { style: { background: '#f9fafb', borderRadius: '8px', padding: '12px', display: 'flex', flexDirection: 'column', gap: '12px' } },
        React.createElement('div', { style: { fontSize: '12px', fontWeight: 600, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em' } }, 'Ticket Details'),
        selected ? React.createElement(React.Fragment, null,
          React.createElement('div', { style: { background: '#fff', borderRadius: '6px', padding: '12px', border: '1px solid #e5e7eb' } },
            React.createElement('div', { style: { fontWeight: 600, fontSize: '14px', color: '#111827', marginBottom: '8px' } }, '#', selected.id, ' ', selected.subject),
            React.createElement('div', { style: { fontSize: '12px', color: '#374151', marginBottom: '4px' } }, 'Requester: ', selected.requester),
            React.createElement('div', { style: { fontSize: '12px', color: '#374151', marginBottom: '4px' } }, 'Priority: ', React.createElement('span', { style: { color: priorityColor(selected.priority), fontWeight: 700 } }, selected.priority)),
            React.createElement('div', { style: { fontSize: '12px', color: '#374151' } }, 'Status: ', React.createElement('span', { style: { color: statusColor(selected.status), fontWeight: 700 } }, selected.status))
          ),
          React.createElement('div', { style: { display: 'flex', gap: '6px' } },
            ['open', 'pending', 'resolved', 'closed'].map(s => React.createElement('button', {
              key: s,
              onClick: () => updateStatus(selected.id, s),
              style: {
                flex: 1,
                fontSize: '11px',
                padding: '6px',
                borderRadius: '4px',
                border: '1px solid ' + statusColor(s),
                background: selected.status === s ? statusColor(s) : '#fff',
                color: selected.status === s ? '#fff' : statusColor(s),
                cursor: 'pointer',
                fontWeight: 600
              }
            }, s))
          ),
          React.createElement('textarea', {
            value: reply,
            onChange: e => setReply(e.target.value),
            placeholder: 'Type your reply...',
            style: { flex: 1, minHeight: '80px', fontSize: '12px', padding: '8px', borderRadius: '4px', border: '1px solid #d1d5db', resize: 'vertical', fontFamily: 'system-ui, sans-serif' }
          }),
          React.createElement('button', { onClick: sendReply, style: { fontSize: '12px', padding: '8px', borderRadius: '4px', border: 'none', background: '#2563eb', color: '#fff', cursor: 'pointer', fontWeight: 600 } }, 'Send Reply')
        ) : React.createElement('div', { style: { color: '#9ca3af', fontSize: '13px', textAlign: 'center', padding: '20px' } }, 'Select a ticket to view details')
      )
    )
  );
};
render(<AgentSupport/>);
